//! Utils for testing using Automated Cryptographic Validation Protocol (ACVP).

use serde::{Deserialize, Serialize};

use crate::test::common::cached_url::CachedUrlResource;

#[derive(Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct AcvpTests {
    vs_id: u32,
    algorithm: String,
    mode: String,
    revision: String,
    is_sample: bool,
    test_groups: Vec<AcvpTestGroup>,
}

impl AcvpTests {
    pub fn get_vs_id(&self) -> u32 {
        self.vs_id
    }

    pub fn get_algorithm(&self) -> &str {
        &self.algorithm
    }

    pub fn get_mode(&self) -> &str {
        &self.mode
    }

    pub fn get_revision(&self) -> &str {
        &self.revision
    }

    pub fn get_is_sample(&self) -> bool {
        self.is_sample
    }

    pub fn get_test_groups(&self) -> &[AcvpTestGroup] {
        &self.test_groups
    }
}

#[serde_with::serde_as]
#[derive(Serialize, Deserialize)]
#[serde(untagged)]
pub enum AcvpTestGroup {
    #[serde(rename_all = "camelCase")]
    KeyGen {
        //#[serde(rename = "tgId")]
        tg_id: u32,
        //#[serde(rename = "testType")]
        test_type: String,
        //#[serde(rename = "parameterSet")]
        parameter_set: String,
        tests: Vec<AcvpKeyGenTestData>,
    },
    #[serde(rename_all = "camelCase")]
    SigGen {
        tg_id: u32,
        test_type: String,
        parameter_set: String,
        deterministic: bool,
        tests: Vec<AcvpSigGenTestData>,
    },
    #[serde(rename_all = "camelCase")]
    SigVer {
        tg_id: u32,
        test_type: String,
        parameter_set: String,
        #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
        pk: Vec<u8>,
        #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
        sk: Vec<u8>,
        tests: Vec<AcvpSigVerTestData>,
    },
}

impl AcvpTestGroup {
    const NAME_KEY_GEN: &'static str = "key_gen";
    const NAME_SIG_GEN: &'static str = "sig_gen";
    const NAME_SIG_VER: &'static str = "sig_ver";

    pub fn name(&self) -> &str {
        match self {
            Self::KeyGen {
                tg_id: _,
                test_type: _,
                parameter_set: _,
                tests: _,
            } => Self::NAME_KEY_GEN,
            Self::SigGen {
                tg_id: _,
                test_type: _,
                parameter_set: _,
                deterministic: _,
                tests: _,
            } => Self::NAME_SIG_GEN,
            Self::SigVer {
                tg_id: _,
                test_type: _,
                parameter_set: _,
                pk: _,
                sk: _,
                tests: _,
            } => Self::NAME_SIG_VER,
        }
    }
}

#[serde_with::serde_as]
#[derive(Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct AcvpKeyGenTestData {
    tc_id: u32,
    deferred: bool,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    seed: Vec<u8>,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    pk: Vec<u8>,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    sk: Vec<u8>,
}

impl AcvpKeyGenTestData {
    pub fn get_tc_id(&self) -> u32 {
        self.tc_id
    }

    pub fn get_deferred(&self) -> bool {
        self.deferred
    }

    pub fn get_seed(&self) -> &[u8] {
        &self.seed
    }

    pub fn get_pk(&self) -> &[u8] {
        &self.pk
    }

    pub fn get_sk(&self) -> &[u8] {
        &self.sk
    }
}

#[serde_with::serde_as]
#[derive(Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct AcvpSigGenTestData {
    tc_id: u32,
    deferred: bool,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    sk: Vec<u8>,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    message: Vec<u8>,
    #[serde(default)]
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    rnd: Vec<u8>,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    signature: Vec<u8>,
}

impl AcvpSigGenTestData {
    pub fn get_tc_id(&self) -> u32 {
        self.tc_id
    }

    pub fn get_deferred(&self) -> bool {
        self.deferred
    }

    pub fn get_sk(&self) -> &[u8] {
        &self.sk
    }

    pub fn get_message(&self) -> &[u8] {
        &self.message
    }

    pub fn get_rnd(&self) -> &[u8] {
        &self.rnd
    }

    pub fn get_signature(&self) -> &[u8] {
        &self.signature
    }
}

#[serde_with::serde_as]
#[derive(Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct AcvpSigVerTestData {
    tc_id: u32,
    test_passed: bool,
    deferred: bool,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    message: Vec<u8>,
    #[serde_as(as = "serde_with::hex::Hex<serde_with::formats::Uppercase>")]
    signature: Vec<u8>,
    reason: String,
}

impl AcvpSigVerTestData {
    pub fn get_tc_id(&self) -> u32 {
        self.tc_id
    }

    pub fn get_test_passed(&self) -> bool {
        self.test_passed
    }

    pub fn get_deferred(&self) -> bool {
        self.deferred
    }

    pub fn get_message(&self) -> &[u8] {
        &self.message
    }

    pub fn get_signature(&self) -> &[u8] {
        &self.signature
    }

    pub fn get_reason(&self) -> &str {
        &self.reason
    }
}

/**
Download any missing ACVP test vectors and cache them locally under `${CARGO_MANIFEST_DIR}/resources/tests`.
 */
pub fn get_acvp_test_data(url: &str) -> Option<AcvpTests> {
    CachedUrlResource::with_resource_dir(&["resources", "tests"])
        .fetch(url)
        .and_then(|contents| {
            serde_json::from_str(&contents)
                .map_err(|e| {
                    log::error!("Failed to deserialize file from '{url}': {e:?}");
                })
                .ok()
        })
}

